#include<bits/stdc++.h>
using namespace std;

int dp[2][100005], n, a[100005], b[100005];

int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	for (int i = 1; i <= n; i++) {
		cin >> b[i];
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			if (a[i] == b[j]) {
				dp[i&1][j] = dp[(i-1)&1][j - 1] + 1;
			} else {
				dp[i&1][j] = max(dp[i&1][j - 1], dp[(i-1)&1][j]);
			}
		}

	}
	cout << dp[n&1][n];
	return 0;
}
